#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <comp421/hardware.h>
#include <comp421/yalnix.h>
#include <comp421/loadinfo.h>

#define STATE_RUNNING 0
#define STATE_READY   1
#define STATE_BLOCKED 2
#define STATE_ZOMBIE  3

/* Global variables */
int vm_enabled = 0;
void *kernel_brk_val;
int next_pid = 2;
struct pte *region1_pt;

typedef struct pcb {
    int pid;
    struct pte *region0_pt;
    SavedContext ctx;
    struct pcb *next;
    struct pcb *prev;
    void *user_brk;
    struct pcb *parent;
    struct pcb *children;
    struct pcb *sibling_next;
    int exit_status;
    int state;
} pcb_t;

pcb_t *current_process = NULL, *idle_pcb = NULL, *init_pcb = NULL;
pcb_t *ready_queue_head = NULL, *ready_queue_tail = NULL;

typedef struct delay_node { pcb_t *pcb; int clock_ticks; struct delay_node *next; } delay_node_t;
delay_node_t *delay_queue = NULL;

typedef struct free_frame { int pfn; struct free_frame *next; } free_frame_t;
free_frame_t *free_frames_head = NULL;
int total_free_frames = 0;

/* Terminal I/O */
typedef struct {
    char buffer[4096];
    int head, tail;
    int line_count;
    pcb_t *read_wait_queue;
} tty_in_t;

typedef struct {
    pcb_t *write_wait_queue;
    int active;
} tty_out_t;

tty_in_t tty_in[NUM_TERMINALS];
tty_out_t tty_out[NUM_TERMINALS];

void (*interrupt_vector[TRAP_VECTOR_SIZE])(ExceptionInfo *);

void trap_kernel_handler(ExceptionInfo *info);
void trap_clock_handler(ExceptionInfo *info);
void trap_illegal_handler(ExceptionInfo *info);
void trap_memory_handler(ExceptionInfo *info);
void trap_math_handler(ExceptionInfo *info);
void trap_tty_receive_handler(ExceptionInfo *info);
void trap_tty_transmit_handler(ExceptionInfo *info);

void scheduler(void);
SavedContext *MySwitchFunc(SavedContext *ctxp, void *p1, void *p2);
int LoadProgram(char *name, char **args, ExceptionInfo *info);

int allocate_frame(void) {
    if (!free_frames_head) return -1;
    free_frame_t *n = free_frames_head;
    int p = n->pfn; free_frames_head = n->next; free(n); total_free_frames--; return p;
}
void free_frame_pfn(int p) {
    free_frame_t *n = (free_frame_t *)malloc(sizeof(free_frame_t));
    n->pfn = p; n->next = free_frames_head; free_frames_head = n; total_free_frames++;
}

void enqueue_ready(pcb_t *p) {
    p->state = STATE_READY; p->next = NULL;
    if (!ready_queue_tail) ready_queue_head = ready_queue_tail = p;
    else { ready_queue_tail->next = p; ready_queue_tail = p; }
}
pcb_t *dequeue_ready(void) {
    if (!ready_queue_head) return NULL;
    pcb_t *p = ready_queue_head; ready_queue_head = p->next;
    if (!ready_queue_head) ready_queue_tail = NULL;
    p->next = NULL; return p;
}

pcb_t *create_pcb(void) {
    pcb_t *p = (pcb_t *)malloc(sizeof(pcb_t));
    p->region0_pt = (struct pte *)malloc(PAGE_TABLE_SIZE);
    for (int i = 0; i < PAGE_TABLE_LEN; i++) {
        unsigned long v = (unsigned long)i << PAGESHIFT;
        if (v >= KERNEL_STACK_BASE && v < KERNEL_STACK_LIMIT) {
            p->region0_pt[i].valid = 1; p->region0_pt[i].pfn = allocate_frame();
            p->region0_pt[i].kprot = PROT_READ|PROT_WRITE; p->region0_pt[i].uprot = PROT_NONE;
        } else p->region0_pt[i].valid = 0;
    }
    p->next = p->prev = p->parent = p->children = p->sibling_next = NULL;
    p->user_brk = (void *)MEM_INVALID_SIZE; p->state = STATE_READY; return p;
}

void scheduler(void) {
    pcb_t *n = dequeue_ready(); if (!n) { if (current_process == idle_pcb) return; n = idle_pcb; }
    pcb_t *prev = current_process; current_process = n; current_process->state = STATE_RUNNING;
    if (ContextSwitch(MySwitchFunc, &prev->ctx, prev, n) == -1) Halt();
}
SavedContext *MySwitchFunc(SavedContext *c, void *p1, void *p2) {
    ((pcb_t *)p1)->ctx = *c; current_process = (pcb_t *)p2; WriteRegister(REG_PTR0, (RCS421RegVal)((pcb_t *)p2)->region0_pt); return &((pcb_t *)p2)->ctx;
}

void do_exit(int s);

int do_fork(void) {
    pcb_t *c = (pcb_t *)malloc(sizeof(pcb_t)); c->pid = next_pid++;
    c->region0_pt = (struct pte *)malloc(PAGE_TABLE_SIZE);
    for (int i = 0; i < PAGE_TABLE_LEN; i++) {
        if (current_process->region0_pt[i].valid) {
            int pfn = allocate_frame(); c->region0_pt[i] = current_process->region0_pt[i]; c->region0_pt[i].pfn = pfn;
            int s = PAGE_TABLE_LEN - 1; region1_pt[s].valid = 1; region1_pt[s].pfn = pfn; region1_pt[s].kprot = PROT_READ|PROT_WRITE;
            WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)(VMEM_1_BASE + (s << PAGESHIFT)));
            memcpy((void *)((unsigned long)VMEM_1_BASE + (s << PAGESHIFT)), (void *)((unsigned long)i << PAGESHIFT), PAGESIZE);
            region1_pt[s].valid = 0; WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)(VMEM_1_BASE + (s << PAGESHIFT)));
        } else c->region0_pt[i].valid = 0;
    }
    pcb_t *p = current_process; c->parent = p; c->sibling_next = p->children; p->children = c;
    c->children = NULL; c->user_brk = p->user_brk; c->state = STATE_READY;
    if (ContextSwitch(MySwitchFunc, &c->ctx, p, c) == 0) { if (current_process == c) return 0; enqueue_ready(c); return c->pid; }
    return ERROR;
}

void do_exit(int s) {
    if (current_process == idle_pcb) Halt();
    current_process->state = STATE_ZOMBIE; current_process->exit_status = s;
    for (int i = 0; i < PAGE_TABLE_LEN; i++) {
        unsigned long v = (unsigned long)i << PAGESHIFT;
        if (v >= KERNEL_STACK_BASE && v < KERNEL_STACK_LIMIT) continue;
        if (current_process->region0_pt[i].valid) { free_frame_pfn(current_process->region0_pt[i].pfn); current_process->region0_pt[i].valid = 0; }
    }
    pcb_t *ch = current_process->children;
    while (ch) { pcb_t *next = ch->sibling_next; ch->parent = init_pcb; ch->sibling_next = init_pcb->children; init_pcb->children = ch; ch = next; }
    current_process->children = NULL;
    if (current_process->parent && current_process->parent->state == STATE_BLOCKED) enqueue_ready(current_process->parent);
    scheduler(); Halt();
}

int do_wait(int *sp) {
    if (!current_process->children) return ERROR;
    while (1) {
        pcb_t *ch = current_process->children, *prev = NULL;
        while (ch) {
            if (ch->state == STATE_ZOMBIE) {
                int pid = ch->pid; if (sp) *sp = ch->exit_status;
                if (!prev) current_process->children = ch->sibling_next; else prev->sibling_next = ch->sibling_next;
                for (int i = 0; i < PAGE_TABLE_LEN; i++) if (ch->region0_pt[i].valid) free_frame_pfn(ch->region0_pt[i].pfn);
                free(ch->region0_pt); free(ch); return pid;
            }
            prev = ch; ch = ch->sibling_next;
        }
        current_process->state = STATE_BLOCKED; scheduler();
    }
}

int do_tty_read(int t, void *b, int l) {
    if (t < 0 || t >= NUM_TERMINALS || l < 0) return ERROR;
    while (tty_in[t].line_count == 0) {
        pcb_t *p = current_process; p->state = STATE_BLOCKED;
        p->next = tty_in[t].read_wait_queue; tty_in[t].read_wait_queue = p;
        scheduler();
    }
    int count = 0;
    while (count < l) {
        char c = tty_in[t].buffer[tty_in[t].head];
        tty_in[t].head = (tty_in[t].head + 1) % 4096;
        ((char *)b)[count++] = c;
        if (c == '\n' || c == '\0') { tty_in[t].line_count--; return count; }
    }
    while (1) {
        char c = tty_in[t].buffer[tty_in[t].head];
        tty_in[t].head = (tty_in[t].head + 1) % 4096;
        if (c == '\n' || c == '\0') { tty_in[t].line_count--; break; }
    }
    return l;
}

int do_tty_write(int t, void *b, int l) {
    if (t < 0 || t >= NUM_TERMINALS || l < 0) return ERROR;
    if (l == 0) return 0;
    while (tty_out[t].active) {
        pcb_t *p = current_process; p->state = STATE_BLOCKED;
        p->next = tty_out[t].write_wait_queue; tty_out[t].write_wait_queue = p;
        scheduler();
    }
    tty_out[t].active = 1;
    for (int i = 0; i < l; i += TERMINAL_MAX_LINE) {
        int n = (l - i > TERMINAL_MAX_LINE) ? TERMINAL_MAX_LINE : l - i;
        TtyTransmit(t, (char *)b + i, n);
        pcb_t *p = current_process; p->state = STATE_BLOCKED;
        p->next = tty_out[t].write_wait_queue; tty_out[t].write_wait_queue = p;
        scheduler();
    }
    tty_out[t].active = 0;
    if (tty_out[t].write_wait_queue) { pcb_t *p = tty_out[t].write_wait_queue; tty_out[t].write_wait_queue = p->next; enqueue_ready(p); }
    return l;
}

int SetKernelBrk(void *a) {
    void *nb = (void *)UP_TO_PAGE(a);
    if (!vm_enabled) kernel_brk_val = nb;
    else {
        while (kernel_brk_val < nb) {
            int p = allocate_frame(); if (p == -1) return -1;
            int v = ((unsigned long)kernel_brk_val - VMEM_1_BASE) >> PAGESHIFT;
            region1_pt[v].pfn = p; region1_pt[v].valid = 1; region1_pt[v].kprot = PROT_READ|PROT_WRITE; region1_pt[v].uprot = PROT_NONE;
            kernel_brk_val = (void *)((unsigned long)kernel_brk_val + PAGESIZE);
        }
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_1);
    }
    return 0;
}

void trap_kernel_handler(ExceptionInfo *info) {
    switch (info->code) {
        case YALNIX_FORK: info->regs[0] = do_fork(); break;
        case YALNIX_EXEC: info->regs[0] = LoadProgram((char *)info->regs[0], (char **)info->regs[1], info); break;
        case YALNIX_EXIT: do_exit((int)info->regs[0]); break;
        case YALNIX_WAIT: info->regs[0] = do_wait((int *)info->regs[0]); break;
        case YALNIX_GETPID: info->regs[0] = current_process->pid; break;
        case YALNIX_DELAY: {
            int t = (int)info->regs[0]; if (t < 0) { info->regs[0] = ERROR; break; }
            if (t == 0) { info->regs[0] = 0; break; }
            delay_node_t *n = (delay_node_t *)malloc(sizeof(delay_node_t)); n->pcb = current_process; n->clock_ticks = t; n->next = delay_queue; delay_queue = n;
            info->regs[0] = 0; current_process->state = STATE_BLOCKED; scheduler(); break;
        }
        case YALNIX_BRK: {
            void *a = (void *)info->regs[0], *nb = (void *)UP_TO_PAGE(a), *ob = (void *)UP_TO_PAGE(current_process->user_brk);
            if (nb < (void *)MEM_INVALID_SIZE || nb >= (void *)USER_STACK_LIMIT) { info->regs[0] = ERROR; break; }
            if (nb > ob) {
                while (ob < nb) {
                    int v = (unsigned long)ob >> PAGESHIFT; if (ob >= (void *)DOWN_TO_PAGE(USER_STACK_LIMIT - PAGESIZE)) { info->regs[0] = ERROR; goto db; }
                    int p = allocate_frame(); if (p == -1) { info->regs[0] = ERROR; goto db; }
                    current_process->region0_pt[v].valid = 1; current_process->region0_pt[v].pfn = p; current_process->region0_pt[v].kprot = PROT_READ|PROT_WRITE; current_process->region0_pt[v].uprot = PROT_READ|PROT_WRITE;
                    ob = (void *)((unsigned long)ob + PAGESIZE);
                }
            } else if (nb < ob) {
                while (ob > nb) { ob = (void *)((unsigned long)ob - PAGESIZE); int v = (unsigned long)ob >> PAGESHIFT; if (current_process->region0_pt[v].valid) { free_frame_pfn(current_process->region0_pt[v].pfn); current_process->region0_pt[v].valid = 0; } }
            }
            current_process->user_brk = a; info->regs[0] = 0; db: WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0); break;
        }
        case YALNIX_TTY_READ: info->regs[0] = do_tty_read((int)info->regs[0], (void *)info->regs[1], (int)info->regs[2]); break;
        case YALNIX_TTY_WRITE: info->regs[0] = do_tty_write((int)info->regs[0], (void *)info->regs[1], (int)info->regs[2]); break;
        default: info->regs[0] = ERROR; break;
    }
}

void trap_clock_handler(ExceptionInfo *i) {
    (void)i; delay_node_t *c = delay_queue, *p = NULL;
    while (c) {
        c->clock_ticks--;
        if (c->clock_ticks <= 0) { enqueue_ready(c->pcb); delay_node_t *tf = c; if (!p) delay_queue = c->next; else p->next = c->next; c = c->next; free(tf); }
        else { p = c; c = c->next; }
    }
    if (current_process != idle_pcb) { enqueue_ready(current_process); }
    scheduler();
}

SavedContext *SaveContextFunc(SavedContext *ctxp, void *p1, void *p2) { (void)p1; (void)p2; return ctxp; }

void trap_illegal_handler(ExceptionInfo *i) { TracePrintf(0, "TRAP_ILLEGAL: %d\n", i->code); do_exit(ERROR); }
void trap_memory_handler(ExceptionInfo *i) {
    unsigned long vaddr = (unsigned long)i->addr;
    int lowest_stack_vpn = PAGE_TABLE_LEN;
    for (int j = (USER_STACK_LIMIT >> PAGESHIFT) - 1; j >= 0; j--) {
        if (current_process->region0_pt[j].valid) lowest_stack_vpn = j;
        else break;
    }
    unsigned long fault_vpn = vaddr >> PAGESHIFT;
    if (fault_vpn < (unsigned long)lowest_stack_vpn && fault_vpn >= ((unsigned long)UP_TO_PAGE(current_process->user_brk) >> PAGESHIFT) + 1) {
        for (int j = lowest_stack_vpn - 1; j >= (int)fault_vpn; j--) {
            int pfn = allocate_frame(); if (pfn == -1) do_exit(ERROR);
            current_process->region0_pt[j].valid = 1; current_process->region0_pt[j].pfn = pfn;
            current_process->region0_pt[j].kprot = PROT_READ|PROT_WRITE; current_process->region0_pt[j].uprot = PROT_READ|PROT_WRITE;
        }
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0); return;
    }
    TracePrintf(0, "TRAP_MEMORY: %d at %p\n", i->code, i->addr); do_exit(ERROR);
}
void trap_math_handler(ExceptionInfo *i) { TracePrintf(0, "TRAP_MATH: %d\n", i->code); do_exit(ERROR); }
void trap_tty_receive_handler(ExceptionInfo *info) {
    int t = info->code; char c; int n = TtyReceive(t, &c, 1);
    if (n == 0) c = '\0';
    tty_in[t].buffer[tty_in[t].tail] = c; tty_in[t].tail = (tty_in[t].tail + 1) % 4096;
    if (c == '\n' || c == '\0') {
        tty_in[t].line_count++;
        while (tty_in[t].read_wait_queue) { pcb_t *p = tty_in[t].read_wait_queue; tty_in[t].read_wait_queue = p->next; enqueue_ready(p); }
    }
}
void trap_tty_transmit_handler(ExceptionInfo *info) {
    int t = info->code;
    if (tty_out[t].write_wait_queue) { pcb_t *p = tty_out[t].write_wait_queue; tty_out[t].write_wait_queue = p->next; enqueue_ready(p); }
}

int LoadProgram(char *n, char **a, ExceptionInfo *info) {
    int fd, i; struct loadinfo li; char *cp, *cp2, **cpp, *ab; unsigned long ac; int sz, tn, dn, sn;
    if ((fd = open(n, O_RDONLY)) < 0) return -1;
    if (LoadInfo(fd, &li) != LI_SUCCESS) { close(fd); return -1; }
    sz = 0; for (i = 0; a[i]; i++) sz += strlen(a[i]) + 1; ac = i;
    cp = ab = (char *)malloc(sz); for (i = 0; a[i]; i++) { strcpy(cp, a[i]); cp += strlen(cp) + 1; }
    cp = ((char *)USER_STACK_LIMIT) - sz; cpp = (char **)((unsigned long)cp & ~0xFL);
    cpp = (char **)((unsigned long)cpp - ((ac + 4) * sizeof(void *)));
    tn = li.text_size >> PAGESHIFT; dn = UP_TO_PAGE(li.data_size + li.bss_size) >> PAGESHIFT; sn = (USER_STACK_LIMIT - DOWN_TO_PAGE(cpp)) >> PAGESHIFT;
    if (MEM_INVALID_PAGES + tn + dn + 1 + sn + 1 + KERNEL_STACK_PAGES > PAGE_TABLE_LEN) { free(ab); close(fd); return -1; }
    int cp_cnt = 0; for (i = 0; i < PAGE_TABLE_LEN; i++) { unsigned long v = (unsigned long)i << PAGESHIFT; if (v >= KERNEL_STACK_BASE && v < KERNEL_STACK_LIMIT) continue; if (current_process && current_process->region0_pt[i].valid) cp_cnt++; }
    if (tn + dn + sn > total_free_frames + cp_cnt) { free(ab); close(fd); return -1; }
    info->sp = (void *)cpp;
    if (current_process) { for (i = 0; i < PAGE_TABLE_LEN; i++) { unsigned long v = (unsigned long)i << PAGESHIFT; if (v >= KERNEL_STACK_BASE && v < KERNEL_STACK_LIMIT) continue; if (current_process->region0_pt[i].valid) { free_frame_pfn(current_process->region0_pt[i].pfn); current_process->region0_pt[i].valid = 0; } } }
    struct pte *pt = current_process ? current_process->region0_pt : init_pcb->region0_pt;
    for (i = 0; i < tn; i++) { pt[MEM_INVALID_PAGES+i].valid = 1; pt[MEM_INVALID_PAGES+i].pfn = allocate_frame(); pt[MEM_INVALID_PAGES+i].kprot = PROT_READ|PROT_WRITE; pt[MEM_INVALID_PAGES+i].uprot = PROT_READ|PROT_EXEC; }
    for (i = 0; i < dn; i++) { pt[MEM_INVALID_PAGES+tn+i].valid = 1; pt[MEM_INVALID_PAGES+tn+i].pfn = allocate_frame(); pt[MEM_INVALID_PAGES+tn+i].kprot = PROT_READ|PROT_WRITE; pt[MEM_INVALID_PAGES+tn+i].uprot = PROT_READ|PROT_WRITE; }
    for (i = 0; i < sn; i++) { int v = (USER_STACK_LIMIT >> PAGESHIFT) - sn + i; pt[v].valid = 1; pt[v].pfn = allocate_frame(); pt[v].kprot = PROT_READ|PROT_WRITE; pt[v].uprot = PROT_READ|PROT_WRITE; }
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
    if (read(fd, (void *)MEM_INVALID_SIZE, li.text_size+li.data_size) != (ssize_t)(li.text_size+li.data_size)) { free(ab); close(fd); return -2; }
    close(fd); for (i = 0; i < tn; i++) pt[MEM_INVALID_PAGES + i].kprot = PROT_READ | PROT_EXEC;
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0); memset((void *)(MEM_INVALID_SIZE + li.text_size + li.data_size), '\0', li.bss_size);
    info->pc = (void *)li.entry; if (current_process) current_process->user_brk = (void *)(MEM_INVALID_SIZE + li.text_size + li.data_size + li.bss_size);
    *cpp++ = (char *)ac; cp2 = ab; for (i = 0; (unsigned long)i < ac; i++) { *cpp++ = cp; strcpy(cp, cp2); cp += strlen(cp)+1; cp2 += strlen(cp2)+1; }
    free(ab); *cpp++ = NULL; *cpp++ = NULL; *cpp++ = 0; for (i = 0; i < NUM_REGS; i++) info->regs[i] = 0; info->psr = 0; return 0;
}

void KernelStart(ExceptionInfo *info, unsigned int pmem_size, void *orig_brk, char **cmd_args) {
    kernel_brk_val = orig_brk; for (int i = 0; i < TRAP_VECTOR_SIZE; i++) interrupt_vector[i] = NULL;
    interrupt_vector[TRAP_KERNEL] = trap_kernel_handler; interrupt_vector[TRAP_CLOCK] = trap_clock_handler;
    interrupt_vector[TRAP_ILLEGAL] = trap_illegal_handler; interrupt_vector[TRAP_MEMORY] = trap_memory_handler;
    interrupt_vector[TRAP_MATH] = trap_math_handler; interrupt_vector[TRAP_TTY_RECEIVE] = trap_tty_receive_handler;
    interrupt_vector[TRAP_TTY_TRANSMIT] = trap_tty_transmit_handler; WriteRegister(REG_VECTOR_BASE, (RCS421RegVal)interrupt_vector);
    region1_pt = (struct pte *)malloc(PAGE_TABLE_SIZE);
    unsigned long ks = VMEM_1_BASE >> PAGESHIFT, ke = UP_TO_PAGE(kernel_brk_val) >> PAGESHIFT, kss = KERNEL_STACK_BASE >> PAGESHIFT, kse = KERNEL_STACK_LIMIT >> PAGESHIFT;
    for (int i = 0; i < (int)(pmem_size >> PAGESHIFT); i++) { if ((i >= (int)kss && i < (int)kse) || (i >= (int)ks && i < (int)ke)) continue; free_frame_pfn(i); }
    for (int i = 0; i < PAGE_TABLE_LEN; i++) {
        unsigned long v = VMEM_1_BASE + ((unsigned long)i << PAGESHIFT);
        if (v < (unsigned long)UP_TO_PAGE(kernel_brk_val)) {
            region1_pt[i].valid = 1; region1_pt[i].pfn = (VMEM_1_BASE >> PAGESHIFT) + i;
            if (v < (unsigned long)&_etext) region1_pt[i].kprot = PROT_READ|PROT_EXEC; else region1_pt[i].kprot = PROT_READ|PROT_WRITE;
            region1_pt[i].uprot = PROT_NONE;
        } else region1_pt[i].valid = 0;
    }
    for (int i = 0; i < NUM_TERMINALS; i++) { tty_in[i].head = tty_in[i].tail = tty_in[i].line_count = 0; tty_in[i].read_wait_queue = NULL; tty_out[i].write_wait_queue = NULL; tty_out[i].active = 0; }
    idle_pcb = create_pcb(); idle_pcb->pid = 0; WriteRegister(REG_PTR0, (RCS421RegVal)idle_pcb->region0_pt);
    if (ContextSwitch(SaveContextFunc, &idle_pcb->ctx, idle_pcb, NULL) == 0) while(1) Pause();
    init_pcb = create_pcb(); init_pcb->pid = 1; current_process = init_pcb;
    WriteRegister(REG_PTR1, (RCS421RegVal)region1_pt); WriteRegister(REG_PTR0, (RCS421RegVal)init_pcb->region0_pt);
    WriteRegister(REG_VM_ENABLE, 1); vm_enabled = 1;
    char *ip = (cmd_args && cmd_args[0]) ? cmd_args[0] : "init";
    if (LoadProgram(ip, cmd_args ? cmd_args : (char *[]){"init", NULL}, info) < 0) Halt();
}

